        public static string? GetRepoRoot()
        {
            string? directory = AppContext.BaseDirectory;

            while (directory is not null)
            {
                var gitPath = Path.Combine(directory, ".git");
                if (Directory.Exists(gitPath) || File.Exists(gitPath))
